InterfaceAsPlainText.xhtml:
PROGRAM MAIN
VAR
    // --- Hardware Inputs ---
    aRawData_ELM3004 AT %I* : ARRAY[1..100] OF REAL; 
    bTrigger_HighSpeed      : BOOL;

    aRawData_ELM3344 AT %I* : ARRAY[1..10] OF REAL; 
    bTrigger_LowSpeed       : BOOL;

    // --- Hardware Outputs ---
    bLamp_Busy_3004 AT %Q*  : BOOL; 
    bLamp_Error_3004 AT %Q* : BOOL;
    bLamp_Busy_3344 AT %Q*  : BOOL; 
    bLamp_Error_3344 AT %Q* : BOOL;

    // --- Configuration ---
    sConfig_FileDir         : STRING := 'C:\Users\101292\Desktop\RF\';
    nConfig_MaxCycles       : UDINT := 100;     
    tConfig_MaxBatchTime    : TIME := T#1M;     // CHANGED: 1 Minute for testing
    tConfig_IdleTimeout     : TIME := T#30M;    

    // --- Internal Objects ---
    stBatchGlobal           : ST_BatchMetadata; 

    fbLogger_3004   : FB_RingData;
    stConf_3004     : ST_SensorMetadata;
    aBuffer_3004    : ARRAY[1..100] OF REAL; 

    fbLogger_3344   : FB_RingData;
    stConf_3344     : ST_SensorMetadata;
    aBuffer_3344    : ARRAY[1..100] OF REAL; 

    // --- Simulation ---
    fbSim           : FB_DataSimulation;
    bSim            : BOOL := FALSE; // CHANGED: Default TRUE for testing
    i               : INT;
END_VAR

ST.xhtml:
// ---------------------------------------------------------
// 0. Simulation
// ---------------------------------------------------------
fbSim(bEnable := bSim);
IF bSim THEN
     aRawData_ELM3004   := fbSim.aSim_ELM3004;
     aRawData_ELM3344   := fbSim.aSim_ELM3344;
     bTrigger_HighSpeed := fbSim.bSimTrigger;
     bTrigger_LowSpeed  := fbSim.bSimTrigger;
END_IF

// ---------------------------------------------------------
// 1. Initialize
// ---------------------------------------------------------
stBatchGlobal.sOrderNumberSAP := 'ORDER_999';

// ---------------------------------------------------------
// 2. Logger 3004
// ---------------------------------------------------------
stConf_3004.sInputModule := 'ELM3004';
stConf_3004.sSensorUnit  := 'G';
stConf_3004.fIncrement   := 0.0001;
aBuffer_3004 := aRawData_ELM3004; 

fbLogger_3004(
    bTrigger            := bTrigger_HighSpeed,
    aValues             := aBuffer_3004,
    nOversamples        := 100,
    sFileDir            := sConfig_FileDir,
    nMaxTrigCycles      := nConfig_MaxCycles,
    tMaxBatchTime       := tConfig_MaxBatchTime,
    tIdleTimeout        := tConfig_IdleTimeout,
    stBatchInfo         := stBatchGlobal,
    stSensorInfo        := stConf_3004
);

bLamp_Busy_3004  := fbLogger_3004.bBusy;
bLamp_Error_3004 := fbLogger_3004.bError;

// ---------------------------------------------------------
// 3. Logger 3344
// ---------------------------------------------------------
stConf_3344.sInputModule := 'ELM3344';
stConf_3344.sSensorUnit  := 'C';
stConf_3344.fIncrement   := 0.001; 
FOR i := 1 TO 10 DO aBuffer_3344[i] := aRawData_ELM3344[i]; END_FOR

fbLogger_3344(
    bTrigger            := bTrigger_LowSpeed,
    aValues             := aBuffer_3344,
    nOversamples        := 10,
    sFileDir            := sConfig_FileDir,
    nMaxTrigCycles      := nConfig_MaxCycles,
    tMaxBatchTime       := tConfig_MaxBatchTime,
    tIdleTimeout        := tConfig_IdleTimeout,
    stBatchInfo         := stBatchGlobal,
    stSensorInfo        := stConf_3344
);

bLamp_Busy_3344  := fbLogger_3344.bBusy;
bLamp_Error_3344 := fbLogger_3344.bError;

